import React, { useEffect, useRef } from "react";
import { MapContainer, TileLayer, Marker, useMap, CircleMarker } from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import "leaflet-routing-machine";

/* 🔵 CUSTOM USER ICON */
const userIcon = new L.DivIcon({
  className: "custom-marker",
  html: `<div class="pulse-marker"></div>`,
  iconSize: [20, 20],
});

/* 🔴 DESTINATION ICON */
const destIcon = new L.DivIcon({
  className: "custom-dest",
  html: `<div class="dest-marker">📍</div>`,
  iconSize: [30, 30],
});

/* ROUTING */
function Routing({ origin, destination, setInfo }) {
  const map = useMap();
  const routingRef = useRef(null);

  useEffect(() => {
    if (!origin || !destination) return;

    if (routingRef.current) {
      map.removeControl(routingRef.current);
    }

    routingRef.current = L.Routing.control({
      waypoints: [
        L.latLng(origin.lat, origin.lon),
        L.latLng(destination.lat, destination.lon),
      ],
      lineOptions: {
        styles: [
          { color: "#ff4f81", weight: 6, opacity: 0.9 },
          { color: "#ffffff", weight: 2, opacity: 0.6 },
        ],
      },
      addWaypoints: false,
      draggableWaypoints: false,
      routeWhileDragging: false,
      show: false,
    })
      .on("routesfound", function (e) {
        const route = e.routes[0];

        const distance = (route.summary.totalDistance / 1000).toFixed(2);
        const time = (route.summary.totalTime / 60).toFixed(0);

        setInfo({ distance, time });

        /* AUTO FIT ROUTE */
        map.fitBounds(route.bounds, { padding: [50, 50] });
      })
      .addTo(map);

  }, [origin, destination]);

  return null;
}

/* MAIN MAP */
function MapView({ origin, destination, setInfo }) {

  if (!origin) return <p className="map-loading">📍 Getting your location...</p>;

  return (
    <div className="map-wrapper">

      <MapContainer
        center={[origin.lat, origin.lon]}
        zoom={15}
        className="map-container"
      >

        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />

        {/* 🔵 USER LOCATION */}
        <Marker position={[origin.lat, origin.lon]} icon={userIcon} />

        {/* 🔵 PULSE RING */}
        <CircleMarker
          center={[origin.lat, origin.lon]}
          radius={20}
          pathOptions={{
            color: "#ff4f81",
            fillColor: "#ff4f81",
            fillOpacity: 0.2,
          }}
        />

        {/* 🔴 DESTINATION */}
        {destination && (
          <Marker
            position={[destination.lat, destination.lon]}
            icon={destIcon}
          />
        )}

        {/* ROUTE */}
        {destination && (
          <Routing
            origin={origin}
            destination={destination}
            setInfo={setInfo}
          />
        )}

      </MapContainer>

    </div>
  );
}

export default MapView;
